/// Deserialize `vectors_accounts.json`, apply each op sequence to a `BinaryTrie`,
/// and compare the computed root against the Python-generated expected root.
///
/// Operations: `set_basic_data`, `set_code_hash`, `clear_stem`.
#[test]
fn verify_accounts_vectors() {
    let json = load_or_skip!("vectors_accounts.json");
    let json = json.as_str();
    let vectors: Vec<AccountVector> =
        serde_json::from_str(json).expect("failed to parse vectors_accounts.json");
    assert!(!vectors.is_empty(), "no account vectors loaded");

    for vector in &vectors {
        let mut trie = BinaryTrie::new();
        apply_account_ops(&mut trie, &vector.ops, &vector.name);

        let root = merkelize(&mut trie);
        let expected = hex_to_32(&vector.expected_root);

        assert_eq!(
            root,
            expected,
            "account vector '{}': root mismatch\n  got:      {}\n  expected: {}",
            vector.name,
            hex::encode(root),
            vector.expected_root,
        );
    }
}

